CREATE OR REPLACE FUNCTION fpb_get_loan_payment_date ( as_conno sc_lon_m_loan_card_detail.loan_contract_no%type , ai_seqno sc_lon_m_loan_card_detail.seq_no%type ) RETURNS timestamp(0) AS $body$
DECLARE

  ls_item_type sc_lon_m_loan_card_detail.item_type_code%type;
  ldtm_payment_date sc_lon_m_loan_card_detail.loan_payment_date%type;
  ldtm_entry_date sc_lon_m_loan_card_detail.entry_date%type;
  ldtm_payment_return timestamp(0);

BEGIN

    select  sc_lon_m_loan_card_detail.item_type_code ,
            sc_lon_m_loan_card_detail.entry_date ,
            sc_lon_m_loan_card_detail.loan_payment_date
    into STRICT    ls_item_type , ldtm_entry_date ,  ldtm_payment_date
    from    sc_lon_m_loan_card_detail
    where   sc_lon_m_loan_card_detail.loan_contract_no = as_conno
    and     sc_lon_m_loan_card_detail.seq_no = ai_seqno;

    --NIGHT 2020/12/18 KTM สอ.กทม.กรณีรหัสรายการ RM ,RC วันที่รายการให้ใช้ entry_date แสดงผล
    if pka.isCoop('KTM') = '1' then
        if ldtm_payment_date < '08/07/2020' then    -- สอ.กทม. วันที่ทำรายการ ก่อนเริ่มใช้ระบบใหม่ใช้ loan_payment_date จะถูกอยู่แล้ว
            ldtm_payment_return := ldtm_payment_date;
        else            
        
            if ls_item_type = 'RC' or ls_item_type = 'RM' then
                ldtm_payment_return := ldtm_entry_date;
            else
                ldtm_payment_return := ldtm_payment_date;
            end if;

        end if;
     else
        ldtm_payment_return := ldtm_payment_date;
     end if;
        
  return ldtm_payment_return;

end;
$body$
